-- ---------------------------------------------------------------- ei-at-work-and-school
insert into public.lessons
  (course_id, slug, title, description, xp_reward, sort_order, unit, content, summary_points)
select
  id,
  'ei-at-work-and-school',
  'EI at work & school',
  'Often the thing that separates good from great — and you don''t need a title.',
  25,
  19,
  7,
  $json$[{"type":"material","title":"The thing that gets you picked","body":"Two people start the same job with the same grades. A year later one's been handed real responsibility and one hasn't. The difference usually isn't smarts.\n\nIt's the stuff this whole course is about: staying calm when things get tense, taking feedback without sulking, reading the room, working well with people who annoy you.\n\nThat's **emotional intelligence at work and school** — and employers rate it sky-high.","image":"/illustrations/growth-mindset.svg","imageAlt":"A sprout growing up a staircase of arrows"},{"type":"material","title":"Manage up and across","body":"You don't just answer to a boss or teacher — you work with them, and with teammates.\n\nThe skill is figuring out what each person actually needs and communicating it before they have to chase you. Stuck on a deadline? Say so early. Confused by an assignment? Ask now, not the night before.\n\nReading what people need and getting ahead of it is half of looking 'great' at anything."},{"type":"true_false","prompt":"You need a title or some kind of authority before you can really lead.","answer":false,"explanation":"Influence comes from trust, listening, and making people feel understood — not from a job title. You can lead from any seat in the room."},{"type":"multiple_choice","prompt":"What's the most emotionally intelligent move?","context":"You're confused about an assignment that's due in a week.","options":["Stay quiet and figure it out alone the night before","Ask a clear question now, while there's still time to fix it","Wait and hope the teacher explains it again","Complain about it to your friends and do nothing"],"correctIndex":1,"explanation":"Communicating proactively shows you're on top of things. Asking early gives everyone time and beats a last-minute scramble."},{"type":"material","title":"Lead without a title","body":"You don't need to be in charge to lead. Real influence isn't bossing people around — it's the opposite.\n\nPeople follow whoever makes them feel **understood**. Listen first. Make others feel heard. Be the one who notices when a teammate is drowning.\n\nThat's how a regular team member ends up being the person everyone actually trusts and turns to — no badge required.","image":"/illustrations/empathy-bridge.svg","imageAlt":"Two heads connected by a bridge, representing perspective-taking"},{"type":"match_pairs","prompt":"Match each situation to the emotionally intelligent response.","pairs":[{"left":"A teammate is clearly stressed","right":"Ask how you can help"},{"left":"You get tough feedback","right":"Listen and say thanks"},{"left":"You made a mistake","right":"Own it out loud"},{"left":"A teammate did great work","right":"Praise it in public"}]},{"type":"categorize","prompt":"Does this build trust with people you work with, or quietly erode it?","categories":["Builds trust","Erodes it"],"items":[{"text":"Owning a mistake the moment you spot it","category":0},{"text":"Listening before you jump in with your fix","category":0},{"text":"Blaming a teammate when something goes wrong","category":1},{"text":"Calling someone out in front of the whole group","category":1},{"text":"Giving credit out loud when someone nails it","category":0},{"text":"Going quiet and hiding a problem you caused","category":1}]},{"type":"material","title":"Praise loud, correct quiet","body":"Two simple rules make you the kind of person people want to work with:\n\n- **Praise in public.** When someone does great work, say it out loud and be specific. 'You kept the whole group calm today' beats a vague 'good job.'\n- **Correct in private.** If someone messed up, pull them aside. Never roast a person in front of the room — embarrassment kills trust fast.\n\nSpecific praise feels real. Quiet correction protects the relationship."},{"type":"multiple_choice","prompt":"A teammate dropped the ball on their part of a group project. Best move?","options":["Call them out in the group chat so everyone sees","Message them privately and ask what happened","Say nothing and silently redo all their work","Tell the teacher before talking to them at all"],"correctIndex":1,"explanation":"Correct in private. A quiet, curious check-in fixes the problem without the humiliation that makes people defensive."},{"type":"material","title":"Be the calm one","body":"Emotions are contagious. When one person panics, the panic spreads — that's **emotional contagion**. The good news: calm spreads the exact same way.\n\nSo when a deadline blows up and everyone's spiraling, the most valuable person in the room is the one who stays steady. One calm person can settle a whole team.\n\nYou don't have to fix everything. Sometimes just not adding to the fire is the win.","image":"/illustrations/anger-thermometer.svg","imageAlt":"A thermometer cooling from hot to calm"},{"type":"tap_word","instructions":"One word flips this rule backwards. Tap it.","sentence":"Owning your mistakes openly builds weakness with the people around you.","wrongWord":"weakness","correctWord":"credibility","explanation":"It's the opposite — owning a mistake openly builds credibility. People trust someone honest about slip-ups far more than someone who hides them."},{"type":"fill_blank","prompt":"Calm and panic both spread through a team the same way — this is called emotional ___.","answer":"contagion","accept":["contageon"],"hint":"Like catching a mood instead of a cold.","explanation":"Emotional contagion means feelings jump between people. That's why one steady person can steady the whole room."},{"type":"order_steps","prompt":"You realize you made a mistake that affected your team. Put the moves in order.","steps":["Notice the mistake and stay calm instead of panicking","Own it openly to the people it affected","Offer a fix or ask how to make it right","Adjust so it doesn't happen the same way again"],"explanation":"Calm, then honest, then helpful. Hiding a mistake costs you trust; owning and fixing it earns it back."},{"type":"multiple_choice","prompt":"Why does staying calm matter so much when a team is stressed?","options":["Emotions are contagious, so your calm can steady everyone","It impresses the boss even if it changes nothing","It means you secretly don't care about the problem","Calm people always get the easiest tasks"],"correctIndex":0,"explanation":"Because of emotional contagion, your steadiness spreads. One composed person can pull a panicking group back to level."},{"type":"material","title":"Protect yourself from burnout","body":"EI isn't only about other people — it's also about noticing your limits. Running yourself into the ground doesn't make you tougher; it makes you worse at everything.\n\nThe skill is catching the early signs of overload and recovering **on purpose**: a real break, sleep, time off your phone, saying no when you're maxed out.\n\nGreat performers aren't the ones who never rest. They're the ones who recover before they crash."},{"type":"decision_path","title":"First week","intro":"New job, new class — fresh start. People are forming their first read on you. Earn their respect.","stat":{"name":"Respect","emoji":"🤝","start":50},"steps":[{"situation":"Your manager gives you tough feedback on your first assignment, in front of two others.","options":[{"text":"Listen, say thanks, and ask what to do differently","delta":20,"feedback":"Taking feedback well is rare and noticed. You just looked coachable.","best":true},{"text":"Get defensive and explain why it's not your fault","delta":-20,"feedback":"Defensiveness tells people feedback bounces off you — so they stop giving it."},{"text":"Go quiet, nod, and quietly decide they're a jerk","delta":-10,"feedback":"Shutting down looks like sulking and you lose the lesson in the feedback."}]},{"situation":"A teammate is visibly stressed and falling behind right before a deadline.","options":[{"text":"Panic out loud about how you'll all miss the deadline","delta":-20,"feedback":"Your panic spreads — emotional contagion works both ways."},{"text":"Stay calm and ask, 'What can I take off your plate?'","delta":20,"feedback":"Calm is contagious, and offering help is how you lead without a title.","best":true},{"text":"Ignore it; it's their part, not your problem","delta":-10,"feedback":"Heads-down indifference reads as 'not a team player' fast."}]},{"situation":"You realize a mistake YOU made is what set the team back.","options":[{"text":"Stay quiet and hope nobody traces it to you","delta":-20,"feedback":"Hiding it is the fastest way to lose trust when it surfaces — and it will."},{"text":"Blame the unclear instructions you were given","delta":-15,"feedback":"Blame-shifting protects your ego and torches your credibility."},{"text":"Own it right away and offer a fix","delta":20,"feedback":"Owning a mistake openly builds credibility — it almost always reads as strength.","best":true}]},{"situation":"A teammate just pulled off a great save under pressure.","options":[{"text":"Praise it out loud and specifically, so the room hears","delta":15,"feedback":"Specific public praise makes people feel seen — and it makes you the person they trust.","best":true},{"text":"Say nothing so the spotlight stays off them and on you","delta":-10,"feedback":"Hogging credit is the quickest way to make a team stop rooting for you."},{"text":"Mutter 'nice' without looking up from your screen","delta":-5,"feedback":"Half-hearted praise barely lands. Specific and out loud is what sticks."}]}],"outro":"No title, no speeches — you stayed calm, took feedback, owned your slip, and lifted the room. That's how respect gets built."}]$json$::jsonb,
  $json$["Stay composed under pressure — one steady person can steady a whole room","Take feedback as info, not an attack, and you'll grow faster than everyone","Lead by trust and listening, not a title — people follow whoever 'gets' them","Praise out loud and specific; correct quietly and in private","Own your mistakes openly — it builds credibility, not weakness"]$json$::jsonb
from public.courses where slug = 'emotional-intelligence'
on conflict (course_id, slug) do update set
  title = excluded.title,
  description = excluded.description,
  xp_reward = excluded.xp_reward,
  sort_order = excluded.sort_order,
  unit = excluded.unit,
  content = excluded.content,
  summary_points = excluded.summary_points;

-- ---------------------------------------------------------------- difficult-people
insert into public.lessons
  (course_id, slug, title, description, xp_reward, sort_order, unit, content, summary_points)
select
  id,
  'difficult-people',
  'Difficult & draining people',
  'You can''t change them — but you can manage your side.',
  25,
  20,
  7,
  $json$[{"type":"material","title":"Some people are just hard","body":"You know the one. The relative who finds the flaw in everything. The coworker who turns every chat into a complaint. The friend who only calls when they need to dump on you.\n\nHere's the hard truth: you can't fix them. People change when they decide to, not when you wish hard enough.\n\nWhat you CAN run is your side of the rope. This lesson is about that.","image":"/illustrations/difficult-people.svg","imageAlt":"A calm figure standing unmoved by storm clouds"},{"type":"material","title":"It's about them","body":"When someone's chronically negative, critical, or baiting you, it feels personal. Usually it isn't.\n\nTheir behavior is about THEIR stuff — their stress, their insecurity, their bad day on repeat. You just happened to be standing there.\n\n**Depersonalizing** is the mental move of not picking up something that was never really yours. It doesn't excuse them. It just stops their mood from becoming your mood."},{"type":"true_false","prompt":"If you're patient and kind enough, you can eventually change a difficult person.","answer":false,"explanation":"You can change how you respond, but not someone else's behavior. People only change when they decide to — chasing that is a trap."},{"type":"multiple_choice","prompt":"What's the healthiest read on what just happened?","context":"Your aunt looks at your plate and says, 'Wow, eating all THAT?' in front of everyone.","options":["This is about her habit of criticizing, not about me","She's right, I should be embarrassed","I need to win this and prove her wrong","Everyone here now agrees with her"],"correctIndex":0,"explanation":"Depersonalizing — seeing the jab as her pattern, not a verdict on you — keeps her comment from running your night."},{"type":"material","title":"Don't take the bait","body":"Some people are fishing. A dig, a guilt trip, a button-pushing comment — they're casting a line, hoping you'll bite so the drama can start.\n\nYour reaction is the fuel. When you stay flat and unbothered — a calm, boring, **grey rock** response — there's nothing for the drama to feed on. It starves.\n\nNot biting isn't weakness. It's refusing to play a game you can't win."},{"type":"tap_word","instructions":"One word is backwards. Tap it.","sentence":"Reacting to someone who is baiting you starves the drama they want.","wrongWord":"starves","correctWord":"feeds","explanation":"Reacting FEEDS the drama — it's the fuel they're fishing for. Staying flat and calm is what starves it."},{"type":"match_pairs","prompt":"Match the difficult behavior to the smarter counter-move.","pairs":[{"left":"Constant baiting and jabs","right":"Stay flat, don't react"},{"left":"Endless negativity","right":"Limit how long you're exposed"},{"left":"Shouting to win","right":"End the conversation calmly"},{"left":"Taking their dig personally","right":"Remember it's about them"}]},{"type":"material","title":"Hold the line","body":"Staying calm doesn't mean taking abuse. The other half is the **boundary** — the limit you set and then actually keep.\n\nA boundary can be small:\n- 'I'm not going to talk about this if you're shouting.'\n- 'I've got ten minutes, then I have to go.'\n- Hanging up. Leaving the room. Muting the chat.\n\nThe magic isn't the sentence — it's holding it. A boundary you don't enforce is just a suggestion.","image":"/illustrations/boundary-line.svg","imageAlt":"A friendly fence marking a limit"},{"type":"categorize","prompt":"Protects your peace, or feeds the drama?","categories":["Protects your peace","Feeds the drama"],"items":[{"text":"Calmly ending a call that turned into shouting","category":0},{"text":"Arguing back to 'win' the point","category":1},{"text":"Muting a group chat that drains you","category":0},{"text":"Replaying their insult all night","category":1},{"text":"Naming a limit and keeping it","category":0},{"text":"Taking the bait every single time","category":1}]},{"type":"i_statement","prompt":"Build a line that holds the boundary without throwing a punch.","context":"A roommate keeps raising their voice at you whenever they're frustrated.","slots":[{"label":"The boundary","options":[{"text":"I'm not going to keep talking","ok":true},{"text":"You need to grow up","ok":false,"why":"That attacks them — now it's a fight, not a boundary."}]},{"label":"The condition","options":[{"text":"if you're shouting at me","ok":true},{"text":"because you're impossible","ok":false,"why":"Labeling them as 'impossible' just invites a bigger blow-up."}]}],"explanation":"A clean boundary names the behavior and your limit — no insult to argue with, so it's harder to drag you into a fight."},{"type":"material","title":"Pick your battles","body":"Not every comment deserves a response. Some you let slide. Some you address later, when it's calm. A rare few are worth a real conversation.\n\nBurning energy on every little dig is exhausting — and it usually gives baiters exactly what they wanted.\n\nAsk yourself: does this actually matter, or do I just want to be right? If it doesn't matter, let it float past. Silence is allowed to be a full answer."},{"type":"multiple_choice","prompt":"What's the move here?","context":"A classmate mutters a sarcastic 'nice job' under their breath after you answer a question. It stings, but it's minor.","options":["Spin around and demand to know what they meant","Let it slide and keep your focus on class","Plan a comeback to humiliate them later","Replay it for the rest of the day"],"correctIndex":1,"explanation":"Picking your battles means letting small jabs float past. Reacting to a tiny dig usually costs you more than the dig itself."},{"type":"material","title":"When it's truly toxic","body":"There's a difference between annoying and toxic. Toxic is the consistent pattern: disrespect, manipulation, leaving you worse every single time.\n\nWith people like that, limiting contact — or stepping away entirely — is allowed. **Protecting your peace isn't cruel.**\n\nAnd empathy doesn't mean being a doormat. You can fully understand why someone is the way they are AND still refuse to let them treat you badly. Both can be true."},{"type":"true_false","prompt":"Choosing to limit or end contact with a consistently toxic person makes you a cruel or unforgiving person.","answer":false,"explanation":"Protecting your peace from someone who repeatedly disrespects or manipulates you is self-respect, not cruelty. Empathy isn't a duty to stay."},{"type":"order_steps","prompt":"Put a draining interaction in the order that protects you best.","steps":["Remind yourself it's about them, not you","Stay calm instead of taking the bait","Name your boundary and hold it","Step away to recover and reset"],"explanation":"Depersonalize, stay flat, hold the line, then recharge — that order keeps you steady and looks after you afterward."},{"type":"reflect","prompt":"Self-awareness cuts both ways. Be honest: is there a situation where YOU might be the difficult one? What's one small thing you could do differently?","context":"We've all been someone's draining person on a bad day.","chips":["Snapping when stressed","Going quiet and cold","Always needing to be right","Venting too much"],"placeholder":"One honest thing I could do differently…","explanation":"The strongest emotional-intelligence move is checking whether the difficult person in the room is sometimes you."},{"type":"decision_path","title":"The difficult one","intro":"There's a chronically critical, negative coworker who loves to bait you. Keep your peace intact.","stat":{"name":"Peace","emoji":"🧘","start":50},"steps":[{"situation":"In the team chat, they post: 'Cute idea, but it'll obviously never work.'","options":[{"text":"Let the jab slide and reply only to the actual idea","delta":15,"feedback":"You didn't take the bait — there's nothing for the drama to feed on.","best":true},{"text":"Fire back a sarcastic comment to win the room","delta":-20,"feedback":"You bit. Now it's a public spat, exactly what they wanted."},{"text":"Spiral about it for the rest of the afternoon","delta":-15,"feedback":"You handed them rent-free space in your head."}]},{"situation":"They corner you after and start loudly listing everything wrong with you.","options":[{"text":"Try to out-argue them point by point","delta":-20,"feedback":"Arguing is fuel. Louder doesn't mean winning."},{"text":"Calmly say you won't talk while they're shouting, then step away","delta":20,"feedback":"Boundary set and held. You ended it without a fight.","best":true},{"text":"Absorb it all and stay silent so they don't get madder","delta":-10,"feedback":"Letting it wash over you isn't a boundary — it's getting soaked."}]},{"situation":"It keeps happening. This person leaves you worse every single time.","options":[{"text":"Keep hoping they'll change if you're nice enough","delta":-15,"feedback":"People change when they choose to, not when you wish harder."},{"text":"Decide to win them over by being their friend","delta":-10,"feedback":"Chasing approval from a baiter just gives them more line."},{"text":"Limit your contact to what work actually requires","delta":20,"feedback":"Protecting your peace from a toxic pattern isn't cruel — it's smart.","best":true}]},{"situation":"That night you still feel rattled and drained.","options":[{"text":"Do something that resets you and let it go","delta":15,"feedback":"Looking after yourself after a draining person is part of the skill.","best":true},{"text":"Replay every comment and stew on it","delta":-15,"feedback":"Re-running it just lets them drain you on overtime."},{"text":"Text three friends to relitigate the whole thing","delta":-10,"feedback":"A little venting helps; marinating in it keeps you stuck."}]}],"outro":"You can't change a difficult person — but staying calm, holding a line, and protecting your peace keeps your number high."}]$json$::jsonb,
  $json$["Depersonalize it: their behavior is usually about them, not you","Stay calm — reacting is the fuel they're fishing for","Set and hold a boundary, and end conversations that turn nasty","Pick your battles; not everything needs a response","With truly toxic people, limiting or ending the relationship is fair game"]$json$::jsonb
